     1→//! Empirical HRF functions for data-driven HRF estimation.
     2→
     3→use crate::error::{HrfError, Result};
     4→use crate::hrf::core::Hrf;
     5→use crate::types::{HrfValues, TimeArray};
     6→use ndarray::{Array1, Array2};
