   119→
   120→/// Empirical HRF implementation.
   121→#[derive(Debug, Clone)]
   122→struct EmpiricalHrf {
   123→    name: String,
   124→    span: f64,
   125→    n_points: usize,
   126→    interpolator: Arc<Interpolator>,
   127→}
   128→
   129→impl Hrf for EmpiricalHrf {
   130→    fn evaluate(&self, t: &TimeArray) -> Result<HrfValues> {
   131→        self.interpolator.interpolate(t)
   132→    }
   133→    
   134→    fn name(&self) -> &str {
   135→        &self.name
   136→    }
   137→    
   138→    fn nbasis(&self) -> usize {
   139→        1
   140→    }
   141→    
   142→    fn span(&self) -> f64 {
   143→        self.span
   144→    }
   145→    
   146→    fn params(&self) -> Vec<(&str, f64)> {
   147→        vec![
   148→            ("n_points", self.n_points as f64),
   149→            ("method", match self.interpolator.method {
   150→                InterpolationMethod::Linear => 0.0,
   151→                InterpolationMethod::Cubic => 1.0,
   152→            }),
   153→        ]
   154→    }
   155→}
   156→
   157→/// Internal interpolator for empirical HRF.
   158→#[derive(Debug, Clone)]
   159→struct Interpolator {
   160→    t: Vec<f64>,
   161→    y: Vec<f64>,
   162→    method: InterpolationMethod,
   163→    // For cubic spline coefficients
   164→    spline_coeffs: Option<SplineCoefficients>,
   165→}
   166→
   167→#[derive(Debug, Clone)]
   168→struct SplineCoefficients {
   169→    a: Vec<f64>,
   170→    b: Vec<f64>,
   171→    c: Vec<f64>,
   172→    d: Vec<f64>,
   173→}
   174→
   175→impl Interpolator {
   176→    fn new(t: Vec<f64>, y: Vec<f64>, method: InterpolationMethod) -> Result<Self> {
   177→        let spline_coeffs = match method {
   178→            InterpolationMethod::Cubic => {
   179→                if t.len() < 4 {
   180→                    return Err(HrfError::InvalidInput(
   181→                        "Cubic interpolation requires at least 4 points".into(),
   182→                    ));
   183→                }
   184→                Some(Self::compute_cubic_spline(&t, &y)?)
   185→            }
   186→            InterpolationMethod::Linear => None,
   187→        };
   188→        
   189→        Ok(Self {
   190→            t,
   191→            y,
   192→            method,
   193→            spline_coeffs,
   194→        })
   195→    }
   196→    
   197→    fn interpolate(&self, t_eval: &TimeArray) -> Result<HrfValues> {
   198→        let mut result = Array2::zeros((t_eval.len(), 1));
   199→        
   200→        for (i, &t_val) in t_eval.iter().enumerate() {
   201→            result[[i, 0]] = self.interpolate_point(t_val);
   202→        }
   203→        
   204→        Ok(result)
   205→    }
   206→    
   207→    fn interpolate_point(&self, t_val: f64) -> f64 {
   208→        // Handle extrapolation - return 0 outside bounds
   209→        if t_val < self.t[0] || t_val > self.t[self.t.len() - 1] {
   210→            return 0.0;
   211→        }
   212→        
   213→        // Find interval containing t_val
   214→        let mut idx = 0;
   215→        for i in 0..self.t.len() - 1 {
   216→            if t_val >= self.t[i] && t_val <= self.t[i + 1] {
   217→                idx = i;
   218→                break;
   219→            }
   220→        }
   221→        
   222→        match self.method {
   223→            InterpolationMethod::Linear => {
   224→                // Linear interpolation
   225→                let t0 = self.t[idx];
   226→                let t1 = self.t[idx + 1];
   227→                let y0 = self.y[idx];
   228→                let y1 = self.y[idx + 1];
   229→                
   230→                let alpha = (t_val - t0) / (t1 - t0);
   231→                y0 * (1.0 - alpha) + y1 * alpha
   232→            }
   233→            InterpolationMethod::Cubic => {
   234→                // Cubic spline interpolation
   235→                if let Some(ref coeffs) = self.spline_coeffs {
   236→                    let dt = t_val - self.t[idx];
   237→                    coeffs.a[idx] + coeffs.b[idx] * dt + coeffs.c[idx] * dt * dt + coeffs.d[idx] * dt * dt * dt
   238→                } else {
   239→                    // Fallback to linear if spline coefficients not available
   240→                    self.linear_interpolate(t_val, idx)
   241→                }
   242→            }
   243→        }
   244→    }
   245→    
   246→    fn linear_interpolate(&self, t_val: f64, idx: usize) -> f64 {
   247→        let t0 = self.t[idx];
   248→        let t1 = self.t[idx + 1];
   249→        let y0 = self.y[idx];
   250→        let y1 = self.y[idx + 1];
   251→        
   252→        let alpha = (t_val - t0) / (t1 - t0);
   253→        y0 * (1.0 - alpha) + y1 * alpha
   254→    }
   255→    
   256→    /// Compute cubic spline coefficients using natural spline boundary conditions.
   257→    fn compute_cubic_spline(t: &[f64], y: &[f64]) -> Result<SplineCoefficients> {
   258→        let n = t.len();
   259→        let mut h = vec![0.0; n - 1];
   260→        let mut alpha = vec![0.0; n - 1];
   261→        
   262→        // Step 1: Calculate h and alpha
   263→        for i in 0..n - 1 {
   264→            h[i] = t[i + 1] - t[i];
   265→            if h[i] <= 0.0 {
   266→                return Err(HrfError::InvalidInput(
   267→                    "Time points must be strictly increasing".into(),
   268→                ));
   269→            }
   270→        }
   271→        
   272→        for i in 1..n - 1 {
   273→            alpha[i] = 3.0 / h[i] * (y[i + 1] - y[i]) - 3.0 / h[i - 1] * (y[i] - y[i - 1]);
   274→        }
   275→        
   276→        // Step 2: Solve tridiagonal system for c coefficients
   277→        let mut l = vec![1.0; n];
   278→        let mut mu = vec![0.0; n];
   279→        let mut z = vec![0.0; n];
   280→        
   281→        for i in 1..n - 1 {
   282→            l[i] = 2.0 * (t[i + 1] - t[i - 1]) - h[i - 1] * mu[i - 1];
   283→            mu[i] = h[i] / l[i];
   284→            z[i] = (alpha[i] - h[i - 1] * z[i - 1]) / l[i];
   285→        }
   286→        
   287→        // Step 3: Back substitution
   288→        let mut c = vec![0.0; n];
   289→        let mut b = vec![0.0; n - 1];
   290→        let mut d = vec![0.0; n - 1];
   291→        let mut a = vec![0.0; n - 1];
   292→        
   293→        for j in (0..n - 1).rev() {
   294→            c[j] = z[j] - mu[j] * c[j + 1];
   295→            b[j] = (y[j + 1] - y[j]) / h[j] - h[j] * (c[j + 1] + 2.0 * c[j]) / 3.0;
   296→            d[j] = (c[j + 1] - c[j]) / (3.0 * h[j]);
   297→            a[j] = y[j];
   298→        }
   299→        
   300→        Ok(SplineCoefficients { a, b, c, d })
   301→    }
   302→}
