     8→/// Generate penalty matrix for regularizing HRF basis coefficients.
     9→///
    10→/// The penalty matrix encodes shape priors that discourage implausible
    11→/// or overly wiggly HRF estimates. Different HRF types use different
    12→/// penalty structures.
    13→///
    14→/// # Arguments
    15→/// * `hrf` - HRF object
    16→/// * `order` - Order of the penalty (default: 2)
    17→/// * `options` - Additional options for specific HRF types
    18→///
    19→/// # Returns
    20→/// Symmetric positive definite penalty matrix of shape (nbasis, nbasis)
    21→pub fn penalty_matrix(
    22→    hrf: &dyn Hrf,
    23→    order: usize,
    24→    options: Option<PenaltyOptions>,
    25→) -> Result<Array2<f64>> {
    26→    let hrf_name = hrf.name().to_uppercase();
    27→    let opts = options.unwrap_or_default();
    28→    
    29→    // Dispatch to specific penalty matrix functions
    30→    match hrf_name.as_str() {
    31→        "SPMG2" | "SPM2" | "SPM_HRF_WITH_DERIVATIVES" | "SPM_WITH_DERIVATIVES" => {
    32→            penalty_spmg2(hrf, order, opts.shrink_deriv)
    33→        }
    34→        "SPMG3" | "SPM3" => {
    35→            penalty_spmg3(hrf, order, opts.shrink_deriv)
    36→        }
    37→        "BSPLINE" | "BS" | "BSPLINE_HRF" => {
    38→            penalty_roughness(hrf, order)
    39→        }
    40→        "FIR" | "TENT" | "FIR_HRF" => {
    41→            penalty_roughness(hrf, order)
    42→        }
    43→        "FOURIER" | "FOURIER_HRF" | "FOURIER_BASIS" => {
    44→            penalty_fourier(hrf, order)
    45→        }
    46→        "DAGUERRE" => {
    47→            penalty_daguerre(hrf, order)
    48→        }
    49→        _ => {
    50→            // Default: identity matrix (ridge penalty)
    51→            Ok(Array2::eye(hrf.nbasis()))
    52→        }
    53→    }
    54→}
    55→
    56→/// Options for penalty matrix generation.
    57→#[derive(Debug, Clone)]
    58→#[cfg_attr(feature = "serde", derive(serde::Serialize, serde::Deserialize))]
    59→pub struct PenaltyOptions {
    60→    /// Shrinkage factor for derivative terms
    61→    pub shrink_deriv: f64,
    62→}
    63→
    64→impl Default for PenaltyOptions {
    65→    fn default() -> Self {
    66→        Self {
    67→            shrink_deriv: 2.0,
    68→        }
    69→    }
    70→}
    71→
    72→/// Roughness penalty based on discrete derivatives.
    73→///
    74→/// Used for FIR, B-spline, and tent basis functions.
    75→fn penalty_roughness(hrf: &dyn Hrf, order: usize) -> Result<Array2<f64>> {
    76→    let nb = hrf.nbasis();
    77→    
    78→    if nb <= 1 {
    79→        Ok(Array2::eye(nb))
    80→    } else if nb > order {
    81→        // Create difference matrix
    82→        let d = create_difference_matrix(nb, order);
    83→        // Return D'D
    84→        Ok(d.t().dot(&d))
    85→    } else {
    86→        Ok(Array2::eye(nb))
    87→    }
    88→}
    89→
    90→/// Create difference matrix of given order.
    91→fn create_difference_matrix(n: usize, order: usize) -> Array2<f64> {
    92→    if order == 0 || n == 0 {
    93→        return Array2::eye(n);
    94→    }
    95→    
    96→    // Start with identity matrix
    97→    let mut mat = Array2::eye(n);
    98→    
    99→    // Apply differencing `order` times
   100→    for _ in 0..order {
   101→        let rows = mat.nrows();
   102→        if rows <= 1 {
   103→            break;
   104→        }
   105→        
   106→        // Create new matrix with one fewer row
   107→        let mut new_mat = Array2::zeros((rows - 1, mat.ncols()));
   108→        
   109→        // Compute differences
   110→        for i in 0..rows - 1 {
   111→            for j in 0..mat.ncols() {
   112→                new_mat[[i, j]] = mat[[i + 1, j]] - mat[[i, j]];
   113→            }
   114→        }
   115→        
   116→        mat = new_mat;
   117→    }
   118→    
   119→    mat
   120→}
   121→
   122→/// Penalty for SPM with temporal derivative.
   123→///
   124→/// Canonical term is not penalized, derivatives are shrunk.
   125→fn penalty_spmg2(hrf: &dyn Hrf, _order: usize, shrink_deriv: f64) -> Result<Array2<f64>> {
   126→    let nb = hrf.nbasis();
   127→    let mut r = Array2::eye(nb);
   128→    
   129→    if nb >= 1 {
   130→        r[[0, 0]] = 0.0; // Don't penalize canonical
   131→    }
   132→    // Shrink all derivatives
   133→    for i in 1..nb {
   134→        r[[i, i]] = shrink_deriv;
   135→    }
   136→    
   137→    Ok(r)
   138→}
   139→
   140→/// Penalty for SPM with temporal and dispersion derivatives.
   141→///
   142→/// Canonical term is not penalized, derivatives are shrunk.
   143→fn penalty_spmg3(hrf: &dyn Hrf, _order: usize, shrink_deriv: f64) -> Result<Array2<f64>> {
   144→    let nb = hrf.nbasis();
   145→    let mut r = Array2::eye(nb);
   146→    
   147→    if nb >= 1 {
   148→        r[[0, 0]] = 0.0; // Don't penalize canonical
   149→    }
   150→    if nb >= 2 {
   151→        r[[1, 1]] = shrink_deriv; // Shrink temporal derivative
   152→    }
   153→    if nb >= 3 {
   154→        r[[2, 2]] = shrink_deriv; // Shrink dispersion derivative
   155→    }
   156→    
   157→    Ok(r)
   158→}
   159→
   160→/// Penalty for Fourier basis.
   161→///
   162→/// Higher frequencies are penalized more.
   163→fn penalty_fourier(hrf: &dyn Hrf, order: usize) -> Result<Array2<f64>> {
   164→    let nb = hrf.nbasis();
   165→    
   166→    // Frequency indices (1, 1, 2, 2, 3, 3, ...)
   167→    let freqs: Vec<f64> = (1..=nb)
   168→        .map(|i| (i as f64 / 2.0).ceil())
   169→        .collect();
   170→    
   171→    // Penalty proportional to frequency^order
   172→    let penalties: Vec<f64> = freqs.iter()
   173→        .map(|&f| f.powi(order as i32))
   174→        .collect();
   175→    
   176→    Ok(Array2::from_diag(&Array1::from_vec(penalties)))
   177→}
   178→
   179→/// Penalty for Daguerre basis.
   180→///
   181→/// Higher order terms are penalized more.
   182→fn penalty_daguerre(hrf: &dyn Hrf, _order: usize) -> Result<Array2<f64>> {
   183→    let nb = hrf.nbasis();
   184→    
   185→    // Penalty increases with basis index
   186→    let penalties: Vec<f64> = (0..nb)
   187→        .map(|i| (i as f64).powi(2))
   188→        .collect();
   189→    
   190→    Ok(Array2::from_diag(&Array1::from_vec(penalties)))
   191→}
   192→
   193→/// Check if a matrix is positive semi-definite.
   194→pub fn is_positive_semidefinite(mat: &Array2<f64>) -> bool {
   195→    if mat.nrows() != mat.ncols() {
   196→        return false;
   197→    }
   198→    
   199→    // Check symmetry
   200→    for i in 0..mat.nrows() {
   201→        for j in i + 1..mat.ncols() {
   202→            if (mat[[i, j]] - mat[[j, i]]).abs() > 1e-10 {
   203→                return false;
   204→            }
   205→        }
   206→    }
   207→    
   208→    // Check eigenvalues
   209→    match mat.clone().eigh_into(UPLO::Lower) {
   210→        Ok((eigenvalues, _)) => {
   211→            eigenvalues.iter().all(|&v| v >= -1e-10)
   212→        }
   213→        Err(_) => false,
   214→    }
   215→}
   216→
   217→/// Generate penalty matrix with automatic order selection.
   218→///
   219→/// Chooses appropriate order based on HRF type and number of basis functions.
   220→pub fn auto_penalty_matrix(hrf: &dyn Hrf) -> Result<Array2<f64>> {
   221→    let order = match hrf.name().to_uppercase().as_str() {
   222→        "FIR" | "FIR_HRF" | "TENT" => 2,
   223→        "BSPLINE" | "BSPLINE_HRF" | "BS" => {
   224→            // Use order = degree + 1
   225→            if let Some(degree) = hrf.params().iter()
   226→                .find(|(name, _)| name == &"degree")
   227→                .map(|(_, val)| *val as usize)
   228→            {
   229→                degree + 1
   230→            } else {
   231→                2
   232→            }
   233→        }
   234→        "FOURIER" | "FOURIER_HRF" => 2,
   235→        _ => 2,
   236→    };
   237→    
   238→    penalty_matrix(hrf, order, None)
   239→}
   240→
   241→#[cfg(test)]
   242→mod tests {
   243→    use super::*;
   244→    use crate::hrf::functions::{spm_hrf_with_derivatives, fir_hrf, bspline_hrf, fourier_hrf};
   245→    use approx::assert_relative_eq;
   246→    
   247→    #[test]
   248→    fn test_penalty_identity() {
   249→        // For unknown HRF types, should return identity
   250→        use crate::hrf::functions::gamma_hrf;
   251→        let hrf = gamma_hrf(6.0, 1.0, Some(true));
   252→        let penalty = penalty_matrix(hrf.as_ref(), 2, None).unwrap();
   253→        
   254→        assert_eq!(penalty.shape(), &[1, 1]);
   255→        assert_eq!(penalty[[0, 0]], 1.0);
   256→    }
   257→    
   258→    #[test]
   259→    fn test_penalty_spmg2() {
   260→        let hrf = spm_hrf_with_derivatives();
   261→        let penalty = penalty_matrix(hrf.as_ref(), 2, None).unwrap();
   262→        
   263→        assert_eq!(penalty.shape(), &[3, 3]);
   264→        // Canonical not penalized
   265→        assert_eq!(penalty[[0, 0]], 0.0);
   266→        // Derivatives penalized
   267→        assert_eq!(penalty[[1, 1]], 2.0);
   268→        assert_eq!(penalty[[2, 2]], 2.0);
   269→    }
   270→    
   271→    #[test]
   272→    fn test_penalty_roughness_fir() {
   273→        let hrf = fir_hrf(5, Some(10.0));
   274→        let penalty = penalty_matrix(hrf.as_ref(), 2, None).unwrap();
   275→        
   276→        assert_eq!(penalty.shape(), &[5, 5]);
   277→        
   278→        // Should be symmetric
   279→        for i in 0..5 {
   280→            for j in i..5 {
   281→                assert_relative_eq!(penalty[[i, j]], penalty[[j, i]], epsilon = 1e-10);
   282→            }
   283→        }
   284→        
   285→        // Should be positive semi-definite
   286→        assert!(is_positive_semidefinite(&penalty));
   287→    }
   288→    
   289→    #[test]
   290→    fn test_penalty_bspline() {
   291→        let hrf = bspline_hrf(4, Some(3), Some(10.0));
   292→        let penalty = penalty_matrix(hrf.as_ref(), 2, None).unwrap();
   293→        
   294→        assert_eq!(penalty.shape(), &[4, 4]);
   295→        assert!(is_positive_semidefinite(&penalty));
   296→    }
   297→    
   298→    #[test]
   299→    fn test_penalty_fourier() {
   300→        let hrf = fourier_hrf(6, Some(10.0));
   301→        let penalty = penalty_matrix(hrf.as_ref(), 2, None).unwrap();
   302→        
   303→        assert_eq!(penalty.shape(), &[6, 6]);
   304→        
   305→        // Check diagonal structure
   306→        for i in 0..6 {
   307→            for j in 0..6 {
   308→                if i != j {
   309→                    assert_eq!(penalty[[i, j]], 0.0);
   310→                }
   311→            }
   312→        }
   313→        
   314→        
   315→        // Check frequency weighting
   316→        assert_eq!(penalty[[0, 0]], 1.0); // freq 1
   317→        assert_eq!(penalty[[1, 1]], 1.0); // freq 1
   318→        assert_eq!(penalty[[2, 2]], 4.0); // freq 2
   319→        assert_eq!(penalty[[3, 3]], 4.0); // freq 2
   320→    }
   321→    
   322→    #[test]
   323→    fn test_difference_matrix() {
   324→        // Test first order differences
   325→        let d1 = create_difference_matrix(4, 1);
   326→        assert_eq!(d1.shape(), &[3, 4]);
   327→        assert_eq!(d1[[0, 0]], -1.0);
   328→        assert_eq!(d1[[0, 1]], 1.0);
   329→        
   330→        // Test second order differences
   331→        let d2 = create_difference_matrix(4, 2);
   332→        assert_eq!(d2.shape(), &[2, 4]);
   333→    }
   334→    
   335→    #[test]
   336→    fn test_auto_penalty() {
   337→        let hrf = fir_hrf(5, Some(10.0));
   338→        let penalty = auto_penalty_matrix(hrf.as_ref()).unwrap();
   339→        
   340→        assert_eq!(penalty.shape(), &[5, 5]);
   341→        assert!(is_positive_semidefinite(&penalty));
   342→    }
   343→    
   344→    #[test]
   345→    fn test_custom_shrink_factor() {
   346→        let hrf = spm_hrf_with_derivatives();
   347→        let opts = PenaltyOptions { shrink_deriv: 5.0 };
   348→        let penalty = penalty_matrix(hrf.as_ref(), 2, Some(opts)).unwrap();
   349→        
   350→        assert_eq!(penalty[[1, 1]], 5.0);
   351→        assert_eq!(penalty[[2, 2]], 5.0);
   352→    }
   353→}

