#[derive(Debug, Clone)]
struct BSplineBasis {
    n_basis: usize,
    degree: usize,
    span: f64,
}

impl Hrf for BSplineBasis {
    fn evaluate(&self, t: &TimeArray) -> Result<HrfValues> {
        // Create knot sequence
        let n_interior = self.n_basis - self.degree + 1;
        let mut knots = Vec::with_capacity(n_interior + 2 * self.degree);

        // Repeated boundary knots
        for _ in 0..self.degree {
            knots.push(0.0);
        }

        // Interior knots
        for i in 0..n_interior {
            knots.push(i as f64 * self.span / (n_interior - 1) as f64);
        }

        // Repeated boundary knots
        for _ in 0..self.degree {
            knots.push(self.span);
        }

        // Evaluate B-spline basis
        let mut basis = Array2::zeros((t.len(), self.n_basis));

        for i in 0..self.n_basis {
            for (j, &time) in t.iter().enumerate() {
                basis[[j, i]] = self.evaluate_bspline_basis(i, self.degree, &knots, time);
            }
        }

        Ok(basis)
    }

    fn name(&self) -> &str {
        "bspline_basis"
    }

    fn nbasis(&self) -> usize {
        self.n_basis
    }

    fn span(&self) -> f64 {
        self.span
    }

    fn params(&self) -> Vec<(&str, f64)> {
        vec![
            ("n_basis", self.n_basis as f64),
            ("degree", self.degree as f64),
            ("span", self.span),
        ]
    }
}

impl BSplineBasis {
    fn evaluate_bspline_basis(&self, i: usize, p: usize, knots: &[f64], t: f64) -> f64 {
        // Cox-de Boor recursion formula
        if p == 0 {
            if i < knots.len() - 1 && t >= knots[i] && t < knots[i + 1] {
                1.0
            } else if i == knots.len() - self.degree - 1 && t == knots[i + 1] {
                // Handle right boundary
                1.0
            } else {
                0.0
            }
        } else {
            let mut result = 0.0;

            // First term
            let denom1 = knots[i + p] - knots[i];
            if denom1 > 0.0 {
                result += (t - knots[i]) / denom1 * self.evaluate_bspline_basis(i, p - 1, knots, t);
            }

            // Second term
            let denom2 = knots[i + p + 1] - knots[i + 1];
            if denom2 > 0.0 {
                result += (knots[i + p + 1] - t) / denom2 * self.evaluate_bspline_basis(i + 1, p - 1, knots, t);
            }

            result
        }
    }
}

/// Create a Fourier basis set HRF.
///
/// # Arguments
/// * `n_basis` - Number of basis functions (must be odd)
/// * `span` - Temporal span of the basis set
pub fn fourier_hrf(
    n_basis: usize,
    span: Option<f64>,
) -> Box<dyn Hrf> {
    let span = span.unwrap_or(20.0);

    Box::new(FourierBasis {
        n_basis,
        span,
    })
}

#[derive(Debug, Clone)]
struct FourierBasis {
