//! HRF function implementations.

use crate::error::{HrfError, Result};
use crate::hrf::core::{Hrf, SimpleHrf};
use crate::types::{HrfValues, TimeArray};
use ndarray::{Array1, Array2, Axis, s};
use statrs::function::gamma::gamma as gamma_fn;
use std::f64::consts::PI;

/// SPM canonical HRF parameters (default values).
/// SPM main response peak parameter
pub const SPM_A1: f64 = 6.0;
/// SPM undershoot peak parameter
pub const SPM_A2: f64 = 16.0;
/// SPM main response width parameter  
pub const SPM_B1: f64 = 1.0;
/// SPM undershoot width parameter
pub const SPM_B2: f64 = 1.0;
/// SPM undershoot ratio parameter
pub const SPM_C: f64 = 1.0 / 6.0;

/// Create the SPM canonical HRF.
///
/// This implements the canonical hemodynamic response function as defined in SPM 
/// (Statistical Parametric Mapping), which is a difference of two gamma functions.
/// The canonical HRF peaks around 5-6 seconds and has an undershoot around 15 seconds.
///
/// # Arguments
/// * `a1` - Shape parameter for positive gamma (default: 6.0)
/// * `a2` - Shape parameter for negative gamma (default: 16.0)
/// * `b1` - Scale parameter for positive gamma (default: 1.0)
/// * `b2` - Scale parameter for negative gamma (default: 1.0)
/// * `c` - Ratio of negative to positive gamma (default: 1/6)
/// * `normalize` - Whether to normalize to unit peak (default: true)
///
/// # Examples
///
/// ```
/// use fmrihrf::hrf::spm_canonical;
/// use ndarray::Array1;
///
/// // Create default SPM canonical HRF
/// let hrf = spm_canonical(None, None, None, None, None, Some(true));
/// 
/// // Evaluate at time points
/// let times = Array1::linspace(0.0, 30.0, 150);
/// let response = hrf.evaluate(&times).unwrap();
/// 
/// // Response peaks around 5-6 seconds
/// let peak_idx = response.iter()
///     .enumerate()
///     .max_by(|(_, a), (_, b)| a.partial_cmp(b).unwrap())
///     .map(|(idx, _)| idx)
///     .unwrap();
/// let peak_time = times[peak_idx];
/// assert!(peak_time > 4.0 && peak_time < 7.0);
/// ```
///
/// # Custom Parameters Example
///
/// ```
/// use fmrihrf::hrf::spm_canonical;
///
/// // Create HRF with slower response (larger a1)
/// let slow_hrf = spm_canonical(
///     Some(8.0),  // Slower rise
///     Some(16.0), // Default undershoot
///     None, None, None, 
///     Some(true)
/// );
/// ```
pub fn spm_canonical(
    a1: Option<f64>,
    a2: Option<f64>,
    b1: Option<f64>,
    b2: Option<f64>,
    c: Option<f64>,
    normalize: Option<bool>,
) -> Box<dyn Hrf> {
    let a1 = a1.unwrap_or(SPM_A1);
    let a2 = a2.unwrap_or(SPM_A2);
    let b1 = b1.unwrap_or(SPM_B1);
    let b2 = b2.unwrap_or(SPM_B2);
    let c = c.unwrap_or(SPM_C);
    let normalize = normalize.unwrap_or(true);

    let params = vec![
        ("a1".to_string(), a1),
        ("a2".to_string(), a2),
        ("b1".to_string(), b1),
        ("b2".to_string(), b2),
        ("c".to_string(), c),
        ("normalize".to_string(), if normalize { 1.0 } else { 0.0 }),
    ];

    Box::new(SimpleHrf::new(
        "spm_canonical",
        1,
        32.0,
        params,
        |t, params| {
            let a1 = params.iter().find(|(k, _)| k == "a1").unwrap().1;
            let a2 = params.iter().find(|(k, _)| k == "a2").unwrap().1;
            let b1 = params.iter().find(|(k, _)| k == "b1").unwrap().1;
            let b2 = params.iter().find(|(k, _)| k == "b2").unwrap().1;
            let c = params.iter().find(|(k, _)| k == "c").unwrap().1;
            let normalize = params.iter().find(|(k, _)| k == "normalize").unwrap().1 > 0.5;

            evaluate_spm_canonical(t, a1, a2, b1, b2, c, normalize)
        },
    ))
}

fn evaluate_spm_canonical(
    t: &TimeArray,
    a1: f64,
    a2: f64,
    b1: f64,
    b2: f64,
    c: f64,
    normalize: bool,
) -> Result<HrfValues> {
    // Validate parameters
    if a1 <= 0.0 || a2 <= 0.0 || b1 <= 0.0 || b2 <= 0.0 {
        return Err(HrfError::InvalidParameters(
            "Shape and scale parameters must be positive".into()
        ));
    }

    let mut hrf = Array1::zeros(t.len());

    for (i, &time) in t.iter().enumerate() {
        if time >= 0.0 {
            // First gamma function (positive)
            let g1 = (time.powf(a1 - 1.0) * b1.powf(a1) * (-b1 * time).exp()) / gamma_fn(a1);

            // Second gamma function (negative)
            let g2 = (time.powf(a2 - 1.0) * b2.powf(a2) * (-b2 * time).exp()) / gamma_fn(a2);

            hrf[i] = g1 - c * g2;
        }
    }

    // Normalize to unit peak if requested
    if normalize {
        let max_val = hrf.fold(f64::NEG_INFINITY, |a, &b| a.max(b.abs()));
        if max_val > 0.0 {
            hrf.mapv_inplace(|v| v / max_val);
        }
    }

    // Convert to 2D array with single column
    Ok(hrf.insert_axis(Axis(1)))
}

/// Create a gamma HRF.
///
/// The gamma distribution is a flexible HRF model that can approximate various
/// hemodynamic response shapes. It's parameterized by shape (α) and scale (β),
/// where the peak time is approximately at (α-1)×β.
///
/// # Arguments
/// * `shape` - Shape parameter (alpha), controls the rise time and peak location
/// * `scale` - Scale parameter (beta), controls the width/spread
/// * `normalize` - Whether to normalize to unit peak (default: true)
///
/// # Examples
///
/// ```
/// use fmrihrf::hrf::gamma_hrf;
/// use ndarray::Array1;
///
/// // Create a gamma HRF with peak around 6 seconds
/// let hrf = gamma_hrf(6.0, 1.0, Some(true));
/// 
/// // Evaluate the HRF
/// let times = Array1::linspace(0.0, 20.0, 100);
/// let response = hrf.evaluate(&times).unwrap();
/// 
/// // The peak should be around (shape-1) * scale = 5 seconds
/// ```
///
/// # Different Response Speeds
///
/// ```
/// use fmrihrf::hrf::gamma_hrf;
///
/// // Fast response (peak ~3s)
/// let fast_hrf = gamma_hrf(4.0, 1.0, None);
/// 
/// // Slow response (peak ~8s)
/// let slow_hrf = gamma_hrf(9.0, 1.0, None);
/// 
/// // Wide response (same peak, broader shape)
/// let wide_hrf = gamma_hrf(3.0, 3.0, None);
/// ```
pub fn gamma_hrf(
    shape: f64,
    scale: f64,
    normalize: Option<bool>,
) -> Box<dyn Hrf> {
    let normalize = normalize.unwrap_or(true);

    let params = vec![
        ("shape".to_string(), shape),
        ("scale".to_string(), scale),
        ("normalize".to_string(), if normalize { 1.0 } else { 0.0 }),
    ];

    Box::new(SimpleHrf::new(
        "gamma_hrf",
        1,
        30.0,
        params,
        |t, params| {
            let shape = params.iter().find(|(k, _)| k == "shape").unwrap().1;
            let scale = params.iter().find(|(k, _)| k == "scale").unwrap().1;
            let normalize = params.iter().find(|(k, _)| k == "normalize").unwrap().1 > 0.5;

            evaluate_gamma_hrf(t, shape, scale, normalize)
        },
    ))
}

fn evaluate_gamma_hrf(
    t: &TimeArray,
    shape: f64,
    scale: f64,
    normalize: bool,
) -> Result<HrfValues> {
    if shape <= 0.0 || scale <= 0.0 {
        return Err(HrfError::InvalidParameters(
            "Shape and scale must be positive".into()
        ));
    }

    let mut hrf = Array1::zeros(t.len());

    for (i, &time) in t.iter().enumerate() {
        if time >= 0.0 {
            hrf[i] = (time.powf(shape - 1.0) * scale.powf(shape) * (-scale * time).exp()) 
                    / gamma_fn(shape);
        }
    }

    if normalize {
        let max_val = hrf.fold(f64::NEG_INFINITY, |a, &b| a.max(b));
        if max_val > 0.0 {
            hrf.mapv_inplace(|v| v / max_val);
        }
    }

    Ok(hrf.insert_axis(Axis(1)))
}

/// Create a Gaussian HRF.
///
/// # Arguments
/// * `center` - Center of the Gaussian
/// * `width` - Width (standard deviation) of the Gaussian
/// * `normalize` - Whether to normalize to unit peak
pub fn gaussian_hrf(
    center: f64,
    width: f64,
    normalize: Option<bool>,
) -> Box<dyn Hrf> {
    let normalize = normalize.unwrap_or(true);

    let params = vec![
        ("center".to_string(), center),
        ("width".to_string(), width),
        ("normalize".to_string(), if normalize { 1.0 } else { 0.0 }),
    ];

    Box::new(SimpleHrf::new(
        "gaussian_hrf",
        1,
        30.0,
        params,
        |t, params| {
            let center = params.iter().find(|(k, _)| k == "center").unwrap().1;
            let width = params.iter().find(|(k, _)| k == "width").unwrap().1;
            let normalize = params.iter().find(|(k, _)| k == "normalize").unwrap().1 > 0.5;

            evaluate_gaussian_hrf(t, center, width, normalize)
        },
    ))
}

fn evaluate_gaussian_hrf(
    t: &TimeArray,
    center: f64,
    width: f64,
    normalize: bool,
) -> Result<HrfValues> {
    if width <= 0.0 {
        return Err(HrfError::InvalidParameters(
            "Width must be positive".into()
        ));
    }

    let variance = width * width;
    let norm_factor = 1.0 / (width * (2.0 * PI).sqrt());

    let hrf = t.mapv(|time| {
        norm_factor * (-(time - center).powi(2) / (2.0 * variance)).exp()
    });

    let mut result = hrf;
    if normalize {
        let max_val = result.fold(f64::NEG_INFINITY, |a, &b| a.max(b));
        if max_val > 0.0 {
            result.mapv_inplace(|v| v / max_val);
        }
    }

    Ok(result.insert_axis(Axis(1)))
}

/// SPM canonical HRF with time and dispersion derivatives.
///
/// Returns a 3-column basis set:
/// 1. Canonical HRF
/// 2. Temporal derivative
/// 3. Dispersion derivative
pub fn spm_hrf_with_derivatives() -> Box<dyn Hrf> {
    Box::new(SpmWithDerivatives::default())
}

#[derive(Debug, Clone)]
struct SpmWithDerivatives {
    a1: f64,
    a2: f64,
    b1: f64,
    b2: f64,
    c: f64,
}

impl Default for SpmWithDerivatives {
    fn default() -> Self {
        Self {
            a1: SPM_A1,
            a2: SPM_A2,
            b1: SPM_B1,
            b2: SPM_B2,
            c: SPM_C,
        }
    }
}

impl Hrf for SpmWithDerivatives {
    fn evaluate(&self, t: &TimeArray) -> Result<HrfValues> {
        let dt = 0.01; // Small time step for numerical derivatives

        // Evaluate canonical HRF
        let canonical = evaluate_spm_canonical(t, self.a1, self.a2, self.b1, self.b2, self.c, true)?;

        // Compute temporal derivative numerically
        let t_plus = t.mapv(|v| v + dt);
        let t_minus = t.mapv(|v| (v - dt).max(0.0));
        let hrf_plus = evaluate_spm_canonical(&t_plus, self.a1, self.a2, self.b1, self.b2, self.c, false)?;
        let hrf_minus = evaluate_spm_canonical(&t_minus, self.a1, self.a2, self.b1, self.b2, self.c, false)?;
        let temporal_deriv = (&hrf_plus - &hrf_minus) / (2.0 * dt);

        // Compute dispersion derivative (change in width)
        let disp_factor = 1.1; // 10% increase in dispersion
        let hrf_disp = evaluate_spm_canonical(
            t, 
            self.a1 / disp_factor, 
            self.a2 / disp_factor, 
            self.b1 / disp_factor, 
            self.b2 / disp_factor, 
            self.c, 
            false
        )?;
        let dispersion_deriv = &hrf_disp - &canonical;

        // Normalize derivatives
        let temp_max = temporal_deriv.fold(f64::NEG_INFINITY, |a, &b| a.max(b.abs()));
        let disp_max = dispersion_deriv.fold(f64::NEG_INFINITY, |a, &b| a.max(b.abs()));

        let mut result = Array2::zeros((t.len(), 3));
        result.slice_mut(s![.., 0]).assign(&canonical.slice(s![.., 0]));

        if temp_max > 0.0 {
            let normalized = temporal_deriv.slice(s![.., 0]).to_owned() / temp_max;
            result.slice_mut(s![.., 1]).assign(&normalized);
        }

        if disp_max > 0.0 {
            let normalized = dispersion_deriv.slice(s![.., 0]).to_owned() / disp_max;
            result.slice_mut(s![.., 2]).assign(&normalized);
        }

        Ok(result)
    }

    fn name(&self) -> &str {
        "spm_with_derivatives"
    }

    fn nbasis(&self) -> usize {
        3
    }

    fn span(&self) -> f64 {
        32.0
    }

    fn params(&self) -> Vec<(&str, f64)> {
        vec![
            ("a1", self.a1),
            ("a2", self.a2),
            ("b1", self.b1),
            ("b2", self.b2),
            ("c", self.c),
        ]
    }
}

/// Create a B-spline basis set HRF.
///
/// Uses the R-compatible splines library for proper B-spline evaluation.
///
/// # Arguments
/// * `n_basis` - Number of basis functions
/// * `degree` - Degree of B-splines (default: 3 for cubic)
/// * `span` - Temporal span of the basis set
pub fn bspline_hrf(
    n_basis: usize,
    degree: Option<usize>,
    span: Option<f64>,
) -> Box<dyn Hrf> {
    let degree = degree.unwrap_or(3);
    let span = span.unwrap_or(20.0);

    Box::new(BSplineBasis {
        n_basis,
        degree,
        span,
    })
}

#[derive(Debug, Clone)]
struct BSplineBasis {
    n_basis: usize,
    degree: usize,
    span: f64,
}

impl Hrf for BSplineBasis {
    fn evaluate(&self, t: &TimeArray) -> Result<HrfValues> {
        use splines::{BSpline, Spline};

        // Create sample points for knot placement (uniform over span)
        let n_samples = std::cmp::max(self.n_basis, 10);
        let sample_points: Vec<f64> = (0..n_samples)
            .map(|i| i as f64 * self.span / (n_samples - 1) as f64)
            .collect();

        // Create B-spline with degrees of freedom matching n_basis
        let spline = BSpline::new(
            &sample_points,
            Some(self.n_basis), // df
            None,                // knots (auto-selected)
            self.degree,
            false,               // no intercept (to match expected n_basis)
            Some((0.0, self.span)) // boundary knots
        ).map_err(|e| HrfError::ComputationError(format!("B-spline creation failed: {}", e)))?;

        // Ensure we got the right number of basis functions
        if spline.n_basis() != self.n_basis {
            return Err(HrfError::ComputationError(
                format!("Expected {} basis functions, got {}", self.n_basis, spline.n_basis())
            ));
        }

        // Convert time array to Vec for splines library
        let t_vec: Vec<f64> = t.to_vec();

        // Get design matrix from splines library
        let design_matrix = spline.design_matrix(&t_vec)
            .map_err(|e| HrfError::ComputationError(format!("B-spline evaluation failed: {}", e)))?;

        // Convert to our expected format
        let basis = if design_matrix.nrows() == t.len() && design_matrix.ncols() == self.n_basis {
            design_matrix
        } else {
            return Err(HrfError::ComputationError(
                format!("Design matrix has wrong dimensions: {}x{}, expected {}x{}", 
                    design_matrix.nrows(), design_matrix.ncols(), t.len(), self.n_basis)
            ));
        };

        Ok(basis)
    }

    fn name(&self) -> &str {
        "bspline_basis"
    }

    fn nbasis(&self) -> usize {
        self.n_basis
    }

    fn span(&self) -> f64 {
        self.span
    }

    fn params(&self) -> Vec<(&str, f64)> {
        vec![
            ("n_basis", self.n_basis as f64),
            ("degree", self.degree as f64),
            ("span", self.span),
        ]
    }
}

impl BSplineBasis {
    fn evaluate_bspline_basis(&self, i: usize, p: usize, knots: &[f64], t: f64) -> f64 {
        // Cox-de Boor recursion formula
        if p == 0 {
            if i < knots.len() - 1 && t >= knots[i] && t < knots[i + 1] {
                1.0
            } else if i == knots.len() - self.degree - 1 && t == knots[i + 1] {
                // Handle right boundary
                1.0
            } else {
                0.0
            }
        } else {
            let mut result = 0.0;

            // First term
            let denom1 = knots[i + p] - knots[i];
            if denom1 > 0.0 {
                result += (t - knots[i]) / denom1 * self.evaluate_bspline_basis(i, p - 1, knots, t);
            }

            // Second term
            let denom2 = knots[i + p + 1] - knots[i + 1];
            if denom2 > 0.0 {
                result += (knots[i + p + 1] - t) / denom2 * self.evaluate_bspline_basis(i + 1, p - 1, knots, t);
            }

            result
        }
    }
}

/// Create a Fourier basis set HRF.
///
/// # Arguments
/// * `n_basis` - Number of basis functions (must be odd)
/// * `span` - Temporal span of the basis set
pub fn fourier_hrf(
    n_basis: usize,
    span: Option<f64>,
) -> Box<dyn Hrf> {
    let span = span.unwrap_or(20.0);

    Box::new(FourierBasis {
        n_basis,
        span,
    })
}

#[derive(Debug, Clone)]
struct FourierBasis {
    n_basis: usize,
    span: f64,
}

impl Hrf for FourierBasis {
    fn evaluate(&self, t: &TimeArray) -> Result<HrfValues> {
        if self.n_basis % 2 == 0 {
            return Err(HrfError::InvalidParameters(
                "n_basis must be odd for Fourier basis (constant + sin/cos pairs)".into()
            ));
        }

        let n_harmonics = (self.n_basis - 1) / 2;
        let mut basis = Array2::zeros((t.len(), self.n_basis));

        // Constant term
        let norm_const = 1.0 / self.span.sqrt();
        for i in 0..t.len() {
            basis[[i, 0]] = norm_const;
        }

        // Sin and cos terms
        let norm_periodic = (2.0 / self.span).sqrt();
        for k in 1..=n_harmonics {
            let omega = 2.0 * PI * k as f64 / self.span;
            for (i, &time) in t.iter().enumerate() {
                basis[[i, 2 * k - 1]] = (omega * time).cos() * norm_periodic;
                basis[[i, 2 * k]] = (omega * time).sin() * norm_periodic;
            }
        }

        Ok(basis)
    }

    fn name(&self) -> &str {
        "fourier_basis"
    }

    fn nbasis(&self) -> usize {
        self.n_basis
    }

    fn span(&self) -> f64 {
        self.span
    }

    fn params(&self) -> Vec<(&str, f64)> {
        vec![
            ("n_basis", self.n_basis as f64),
            ("span", self.span),
        ]
    }
}

/// Create a Finite Impulse Response (FIR) basis set.
///
/// # Arguments
/// * `n_basis` - Number of basis functions
/// * `span` - Temporal span of the basis set
pub fn fir_hrf(
    n_basis: usize,
    span: Option<f64>,
) -> Box<dyn Hrf> {
    let span = span.unwrap_or(20.0);

    Box::new(FirBasis {
        n_basis,
        span,
    })
}

#[derive(Debug, Clone)]
struct FirBasis {
    n_basis: usize,
    span: f64,
}

impl Hrf for FirBasis {
    fn evaluate(&self, t: &TimeArray) -> Result<HrfValues> {
        let bin_width = self.span / self.n_basis as f64;
        let mut basis = Array2::zeros((t.len(), self.n_basis));

        for i in 0..self.n_basis {
            let bin_start = i as f64 * bin_width;
            let bin_end = (i + 1) as f64 * bin_width;

            for (j, &time) in t.iter().enumerate() {
                if time >= bin_start && time < bin_end {
                    basis[[j, i]] = 1.0;
                } else if i == self.n_basis - 1 && time == self.span {
                    // Handle edge case where t == span
                    basis[[j, i]] = 1.0;
                }
            }
        }

        Ok(basis)
    }

    fn name(&self) -> &str {
        "fir_basis"
    }

    fn nbasis(&self) -> usize {
        self.n_basis
    }

    fn span(&self) -> f64 {
        self.span
    }

    fn params(&self) -> Vec<(&str, f64)> {
        vec![
            ("n_basis", self.n_basis as f64),
            ("span", self.span),
        ]
    }
}

/// Create a Mexican hat (Ricker) wavelet HRF.
///
/// # Arguments
/// * `sigma` - Width parameter
/// * `center` - Center of the wavelet
pub fn mexhat_hrf(
    sigma: f64,
    center: f64,
) -> Box<dyn Hrf> {
    let params = vec![
        ("sigma".to_string(), sigma),
        ("center".to_string(), center),
    ];

    Box::new(SimpleHrf::new(
        "mexhat_hrf",
        1,
        30.0,
        params,
        |t, params| {
            let sigma = params.iter().find(|(k, _)| k == "sigma").unwrap().1;
            let center = params.iter().find(|(k, _)| k == "center").unwrap().1;

            evaluate_mexhat_hrf(t, sigma, center)
        },
    ))
}

fn evaluate_mexhat_hrf(
    t: &TimeArray,
    sigma: f64,
    center: f64,
) -> Result<HrfValues> {
    if sigma <= 0.0 {
        return Err(HrfError::InvalidParameters(
            "Sigma must be positive".into()
        ));
    }

    let z = t.mapv(|time| (time - center) / sigma);
    let normalization = 2.0 / ((3.0 * sigma).sqrt() * PI.powf(0.25));
    let hrf = z.mapv(|z| normalization * (1.0 - z * z) * (-z * z / 2.0).exp());

    Ok(hrf.insert_axis(Axis(1)))
}

/// Create a sine wave HRF.
///
/// # Arguments
/// * `frequency` - Frequency in Hz
/// * `phase` - Phase shift in radians
pub fn sine_hrf(
    frequency: f64,
    phase: f64,
) -> Box<dyn Hrf> {
    let params = vec![
        ("frequency".to_string(), frequency),
        ("phase".to_string(), phase),
    ];

    Box::new(SimpleHrf::new(
        "sine_hrf",
        1,
        30.0,
        params,
        |t, params| {
            let frequency = params.iter().find(|(k, _)| k == "frequency").unwrap().1;
            let phase = params.iter().find(|(k, _)| k == "phase").unwrap().1;

            let hrf = t.mapv(|time| (2.0 * PI * frequency * time + phase).sin());
            Ok(hrf.insert_axis(Axis(1)))
        },
    ))
}

/// Create a half-cosine HRF.
///
/// # Arguments
/// * `width` - Width of the half-cosine
/// * `center` - Center of the function
pub fn half_cosine_hrf(
    width: f64,
    center: f64,
) -> Box<dyn Hrf> {
    let params = vec![
        ("width".to_string(), width),
        ("center".to_string(), center),
    ];

    Box::new(SimpleHrf::new(
        "half_cosine_hrf",
        1,
        30.0,
        params,
        |t, params| {
            let width = params.iter().find(|(k, _)| k == "width").unwrap().1;
            let center = params.iter().find(|(k, _)| k == "center").unwrap().1;

            evaluate_half_cosine_hrf(t, width, center)
        },
    ))
}

fn evaluate_half_cosine_hrf(
    t: &TimeArray,
    width: f64,
    center: f64,
) -> Result<HrfValues> {
    if width <= 0.0 {
        return Err(HrfError::InvalidParameters(
            "Width must be positive".into()
        ));
    }

    let t_start = center - width / 2.0;
    let t_end = center + width / 2.0;

    let hrf = t.mapv(|time| {
        if time >= t_start && time <= t_end {
            let scaled_t = (time - t_start) * PI / width;
            0.5 * (1.0 + scaled_t.cos())
        } else {
            0.0
        }
    });

    Ok(hrf.insert_axis(Axis(1)))
}

/// Create an inverse logit (sigmoid) HRF.
///
/// # Arguments
/// * `center` - Center of the sigmoid
/// * `scale` - Scale parameter (smaller = steeper)
pub fn inv_logit_hrf(
    center: f64,
    scale: f64,
) -> Box<dyn Hrf> {
    let params = vec![
        ("center".to_string(), center),
        ("scale".to_string(), scale),
    ];

    Box::new(SimpleHrf::new(
        "inv_logit_hrf",
        1,
        30.0,
        params,
        |t, params| {
            let center = params.iter().find(|(k, _)| k == "center").unwrap().1;
            let scale = params.iter().find(|(k, _)| k == "scale").unwrap().1;

            evaluate_inv_logit_hrf(t, center, scale)
        },
    ))
}

fn evaluate_inv_logit_hrf(
    t: &TimeArray,
    center: f64,
    scale: f64,
) -> Result<HrfValues> {
    if scale <= 0.0 {
        return Err(HrfError::InvalidParameters(
            "Scale must be positive".into()
        ));
    }

    let hrf = t.mapv(|time| 1.0 / (1.0 + ((center - time) / scale).exp()));
    Ok(hrf.insert_axis(Axis(1)))
}

/// Lag-Width-Undershoot (LWU) HRF.
///
/// Computes the LWU hemodynamic response function using two Gaussian
/// components to model the main response and an optional undershoot.
///
/// Formula:
/// h(t; τ, σ, ρ) = exp(-(t-τ)²/(2σ²)) - ρ*exp(-(t-τ-2σ)²/(2(1.6σ)²))
///
/// # Arguments
/// * `tau` - Lag of main Gaussian, time-to-peak (default: 6.0)
/// * `sigma` - Width of main Gaussian, must be > 0.05 (default: 2.5)
/// * `rho` - Amplitude of undershoot, 0 to 1.5 (default: 0.35)
/// * `normalize` - Normalization type: "none" or "height" (default: "none")
pub fn lwu_hrf(
    tau: Option<f64>,
    sigma: Option<f64>,
    rho: Option<f64>,
    normalize: Option<&str>,
) -> Result<Box<dyn Hrf>> {
    let tau = tau.unwrap_or(6.0);
    let sigma = sigma.unwrap_or(2.5);
    let rho = rho.unwrap_or(0.35);
    let normalize = normalize.unwrap_or("none");

    // Validate parameters
    if sigma <= 0.05 {
        return Err(HrfError::InvalidParameters("sigma must be > 0.05".into()));
    }
    if !(0.0..=1.5).contains(&rho) {
        return Err(HrfError::InvalidParameters("rho must be between 0 and 1.5".into()));
    }
    if !["none", "height"].contains(&normalize) {
        return Err(HrfError::InvalidParameters("normalize must be 'none' or 'height'".into()));
    }

    let normalize_height = normalize == "height";
    let params = vec![
        ("tau".to_string(), tau),
        ("sigma".to_string(), sigma),
        ("rho".to_string(), rho),
        ("normalize".to_string(), if normalize_height { 1.0 } else { 0.0 }),
    ];

    Ok(Box::new(SimpleHrf::new(
        "lwu_hrf",
        1,
        30.0,
        params,
        move |t, params| {
            let tau = params.iter().find(|(k, _)| k == "tau").unwrap().1;
            let sigma = params.iter().find(|(k, _)| k == "sigma").unwrap().1;
            let rho = params.iter().find(|(k, _)| k == "rho").unwrap().1;
            let normalize_height = params.iter().find(|(k, _)| k == "normalize").unwrap().1 > 0.5;

            evaluate_lwu_hrf(t, tau, sigma, rho, normalize_height)
        },
    )))
}

fn evaluate_lwu_hrf(
    t: &TimeArray,
    tau: f64,
    sigma: f64,
    rho: f64,
    normalize_height: bool,
) -> Result<HrfValues> {
    // Main positive Gaussian component
    let term1 = t.mapv(|t| (-(t - tau).powi(2) / (2.0 * sigma.powi(2))).exp());

    // Undershoot Gaussian component
    let term2 = t.mapv(|t| {
        rho * (-(t - (tau + 2.0 * sigma)).powi(2) / (2.0 * (1.6 * sigma).powi(2))).exp()
    });

    let mut response = term1 - term2;

    if normalize_height {
        let max_abs_val = response.fold(f64::NEG_INFINITY, |a, &b| a.max(b.abs()));
        if max_abs_val > 1e-10 {
            response /= max_abs_val;
        }
    }

    Ok(response.insert_axis(Axis(1)))
}

/// LWU HRF basis for Taylor expansion.
///
/// Constructs the basis set for the LWU HRF model, consisting of the
/// LWU HRF evaluated at expansion point theta0 and its partial derivatives.
///
/// # Arguments
/// * `theta0` - Expansion point [tau0, sigma0, rho0]
/// * `normalize_primary` - Normalization for primary HRF: "none" or "height" (default: "none")
pub fn hrf_basis_lwu(
    theta0: &[f64; 3],
    normalize_primary: Option<&str>,
) -> Result<Box<dyn Hrf>> {
    let [tau0, sigma0, rho0] = *theta0;
    let normalize_primary = normalize_primary.unwrap_or("none");

    // Validate parameters
    if sigma0 <= 0.05 {
        return Err(HrfError::InvalidParameters("sigma0 must be > 0.05".into()));
    }
    if !(0.0..=1.5).contains(&rho0) {
        return Err(HrfError::InvalidParameters("rho0 must be between 0 and 1.5".into()));
    }

    let params = vec![
        ("tau0".to_string(), tau0),
        ("sigma0".to_string(), sigma0),
        ("rho0".to_string(), rho0),
        ("normalize_primary".to_string(), if normalize_primary == "height" { 1.0 } else { 0.0 }),
    ];

    Ok(Box::new(SimpleHrf::new(
        "hrf_basis_lwu",
        4,
        30.0,
        params,
        move |t, params| {
            let tau0 = params.iter().find(|(k, _)| k == "tau0").unwrap().1;
            let sigma0 = params.iter().find(|(k, _)| k == "sigma0").unwrap().1;
            let rho0 = params.iter().find(|(k, _)| k == "rho0").unwrap().1;
            let normalize_primary = params.iter().find(|(k, _)| k == "normalize_primary").unwrap().1 > 0.5;

            evaluate_hrf_basis_lwu(t, tau0, sigma0, rho0, if normalize_primary { "height" } else { "none" })
        },
    )))
}

fn evaluate_hrf_basis_lwu(
    t: &TimeArray,
    tau0: f64,
    sigma0: f64,
    rho0: f64,
    normalize_primary: &str,
) -> Result<HrfValues> {
    let n_times = t.len();
    let mut basis = Array2::zeros((n_times, 4));

    // Primary HRF at expansion point
    let h0 = lwu_hrf(Some(tau0), Some(sigma0), Some(rho0), Some(normalize_primary))?;
    let h0_values = h0.evaluate(t)?;
    basis.slice_mut(s![.., 0]).assign(&h0_values.slice(s![.., 0]));

    // Compute partial derivatives numerically
    let eps = 1e-5;

    // Partial derivative w.r.t. tau
    let h_tau_plus = lwu_hrf(Some(tau0 + eps), Some(sigma0), Some(rho0), Some("none"))?;
    let h_tau_minus = lwu_hrf(Some(tau0 - eps), Some(sigma0), Some(rho0), Some("none"))?;
    let h_tau_plus_values = h_tau_plus.evaluate(t)?;
    let h_tau_minus_values = h_tau_minus.evaluate(t)?;
    let dh_dtau = (&h_tau_plus_values.slice(s![.., 0]) - &h_tau_minus_values.slice(s![.., 0])) / (2.0 * eps);
    basis.slice_mut(s![.., 1]).assign(&dh_dtau);

    // Partial derivative w.r.t. sigma
    let h_sigma_plus = lwu_hrf(Some(tau0), Some(sigma0 + eps), Some(rho0), Some("none"))?;
    let h_sigma_minus = lwu_hrf(Some(tau0), Some(sigma0 - eps), Some(rho0), Some("none"))?;
    let h_sigma_plus_values = h_sigma_plus.evaluate(t)?;
    let h_sigma_minus_values = h_sigma_minus.evaluate(t)?;
    let dh_dsigma = (&h_sigma_plus_values.slice(s![.., 0]) - &h_sigma_minus_values.slice(s![.., 0])) / (2.0 * eps);
    basis.slice_mut(s![.., 2]).assign(&dh_dsigma);

    // Partial derivative w.r.t. rho
    let h_rho_plus = lwu_hrf(Some(tau0), Some(sigma0), Some(rho0 + eps), Some("none"))?;
    let h_rho_minus = lwu_hrf(Some(tau0), Some(sigma0), Some(rho0 - eps), Some("none"))?;
    let h_rho_plus_values = h_rho_plus.evaluate(t)?;
    let h_rho_minus_values = h_rho_minus.evaluate(t)?;
    let dh_drho = (&h_rho_plus_values.slice(s![.., 0]) - &h_rho_minus_values.slice(s![.., 0])) / (2.0 * eps);
    basis.slice_mut(s![.., 3]).assign(&dh_drho);

    Ok(basis)
}

/// Time HRF - Linear function of time.
///
/// Simple linear function of time when t is between 0 and maxt.
///
/// # Arguments
/// * `maxt` - Maximum time point in the domain (default: 22.0)
pub fn hrf_time(maxt: Option<f64>) -> Box<dyn Hrf> {
    let maxt = maxt.unwrap_or(22.0);
    let params = vec![("maxt".to_string(), maxt)];

    Box::new(SimpleHrf::new(
        "hrf_time",
        1,
        maxt,
        params,
        move |t, params| {
            let maxt = params.iter().find(|(k, _)| k == "maxt").unwrap().1;
            let values = t.mapv(|t| if t > 0.0 && t < maxt { t } else { 0.0 });
            Ok(values.insert_axis(Axis(1)))
        },
    ))
}

#[cfg(test)]
mod tests {
    use super::*;
    use approx::assert_relative_eq;

    #[test]
    fn test_spm_canonical() {
        let hrf = spm_canonical(None, None, None, None, None, None);
        let t = Array1::linspace(0.0, 20.0, 21);
        let result = hrf.evaluate(&t).unwrap();

        assert_eq!(result.shape(), &[21, 1]);

        // Should peak around 5-6 seconds
        let (max_idx, _) = result.iter()
            .enumerate()
            .max_by(|(_, a), (_, b)| a.partial_cmp(b).unwrap())
            .unwrap();
        assert!(max_idx >= 4 && max_idx <= 7);

        // Should be normalized to peak of 1
        let max_val = result.fold(f64::NEG_INFINITY, |a, &b| a.max(b));
        assert_relative_eq!(max_val, 1.0, epsilon = 1e-6);
    }

    #[test]
    fn test_gamma_hrf() {
        let hrf = gamma_hrf(6.0, 1.0, Some(true));
        let t = Array1::linspace(0.0, 20.0, 21);
        let result = hrf.evaluate(&t).unwrap();

        assert_eq!(result.shape(), &[21, 1]);

        // Should be normalized
        let max_val = result.fold(f64::NEG_INFINITY, |a, &b| a.max(b));
        assert_relative_eq!(max_val, 1.0, epsilon = 1e-6);
    }

    #[test]
    fn test_gaussian_hrf() {
        let hrf = gaussian_hrf(5.0, 2.0, Some(true));
        let t = Array1::linspace(0.0, 10.0, 11);
        let result = hrf.evaluate(&t).unwrap();

        assert_eq!(result.shape(), &[11, 1]);

        // Should peak at center (t=5)
        assert_relative_eq!(result[[5, 0]], 1.0, epsilon = 1e-6);
    }

    #[test]
    fn test_spm_with_derivatives() {
        let hrf = spm_hrf_with_derivatives();
        let t = Array1::linspace(0.0, 20.0, 21);
        let result = hrf.evaluate(&t).unwrap();

        assert_eq!(result.shape(), &[21, 3]);
        assert_eq!(hrf.nbasis(), 3);

        // First column should be canonical HRF
        let canonical_max = result.column(0).fold(f64::NEG_INFINITY, |a, &b| a.max(b));
        assert_relative_eq!(canonical_max, 1.0, epsilon = 1e-6);
    }

    #[test]
    fn test_bspline_hrf() {
        let hrf = bspline_hrf(5, Some(3), Some(20.0));
        let t = Array1::linspace(0.0, 20.0, 21);
        let result = hrf.evaluate(&t).unwrap();

        assert_eq!(result.shape(), &[21, 5]);
        assert_eq!(hrf.nbasis(), 5);

        // Check that basis functions sum to approximately 1 (partition of unity)
        for i in 5..15 { // Check interior points
            let sum: f64 = (0..5).map(|j| result[[i, j]]).sum();
            assert!(sum > 0.9 && sum < 1.1, "B-spline partition of unity violated at t={}", t[i]);
        }
    }

    #[test]
    fn test_fourier_hrf() {
        let hrf = fourier_hrf(5, Some(20.0));
        let t = Array1::linspace(0.0, 20.0, 21);
        let result = hrf.evaluate(&t).unwrap();

        assert_eq!(result.shape(), &[21, 5]);
        assert_eq!(hrf.nbasis(), 5);

        // Check orthogonality (approximately)
        let dt = 20.0 / 20.0; // Approximate integral
        for i in 0..5 {
            for j in i+1..5 {
                let inner_product: f64 = (0..21).map(|k| result[[k, i]] * result[[k, j]] * dt).sum();
                assert!(inner_product.abs() < 0.1, "Fourier basis not orthogonal: <{}, {}> = {}", i, j, inner_product);
            }
        }
    }

    #[test]
    fn test_fir_hrf() {
        let hrf = fir_hrf(10, Some(20.0));
        let t = Array1::linspace(0.0, 20.0, 21);
        let result = hrf.evaluate(&t).unwrap();

        assert_eq!(result.shape(), &[21, 10]);
        assert_eq!(hrf.nbasis(), 10);

        // Check that each time point activates exactly one basis function
        for i in 0..20 { // Exclude last point which is edge case
            let active_count: usize = (0..10).filter(|&j| result[[i, j]] > 0.0).count();
            assert_eq!(active_count, 1, "FIR basis should have exactly one active function at each time");
        }
    }

    #[test]
    fn test_mexhat_hrf() {
        let hrf = mexhat_hrf(2.0, 6.0);
        let t = Array1::linspace(0.0, 20.0, 21);
        let result = hrf.evaluate(&t).unwrap();

        assert_eq!(result.shape(), &[21, 1]);

        // Mexican hat should have negative values
        let has_negative = result.iter().any(|&v| v < 0.0);
        assert!(has_negative, "Mexican hat should have negative values");

        // Peak should be around center
        let (max_idx, _) = result.iter()
            .enumerate()
            .max_by(|(_, a), (_, b)| a.partial_cmp(b).unwrap())
            .unwrap();
        assert!(max_idx >= 4 && max_idx <= 8); // Peak around t=6
    }

    #[test]
    fn test_sine_hrf() {
        let hrf = sine_hrf(0.5, 0.0);
        let t = Array1::linspace(0.0, 4.0, 41); // Two complete cycles
        let result = hrf.evaluate(&t).unwrap();

        assert_eq!(result.shape(), &[41, 1]);

        // Check periodicity
        assert_relative_eq!(result[[0, 0]], result[[20, 0]], epsilon = 1e-6); // t=0 and t=2
        assert_relative_eq!(result[[10, 0]], result[[30, 0]], epsilon = 1e-6); // t=1 and t=3
    }

    #[test]
    fn test_half_cosine_hrf() {
        let hrf = half_cosine_hrf(10.0, 5.0);
        let t = Array1::linspace(0.0, 10.0, 11);
        let result = hrf.evaluate(&t).unwrap();

        assert_eq!(result.shape(), &[11, 1]);

        // Half-cosine centered at 5 with width 10 spans [0, 10]
        // At t=0 (start), cos(0) after shift gives max value
        assert_relative_eq!(result[[0, 0]], 1.0, epsilon = 1e-6);
        // At t=10 (end), should approach 0
        assert!(result[[10, 0]].abs() < 1e-6);

        // Peak should be at start (t=0) for this half-cosine
        let (max_idx, _) = result.iter()
            .enumerate()
            .max_by(|(_, a), (_, b)| a.partial_cmp(b).unwrap())
            .unwrap();
        assert_eq!(max_idx, 0); // Peak at t=0 for half-cosine starting at max
    }

    #[test]
    fn test_inv_logit_hrf() {
        let hrf = inv_logit_hrf(6.0, 1.0);
        let t = Array1::linspace(0.0, 12.0, 13);
        let result = hrf.evaluate(&t).unwrap();

        assert_eq!(result.shape(), &[13, 1]);

        // Should be monotonically increasing
        for i in 1..13 {
            assert!(result[[i, 0]] >= result[[i-1, 0]], "Sigmoid should be monotonic");
        }

        // Should be approximately 0.5 at center
        assert_relative_eq!(result[[6, 0]], 0.5, epsilon = 0.01);
    }

    #[test]
    fn test_lwu_hrf() {
        // Test with default parameters
        let hrf = lwu_hrf(None, None, None, None).unwrap();
        assert_eq!(hrf.name(), "lwu_hrf");
        assert_eq!(hrf.nbasis(), 1);

        let t = Array1::linspace(0.0, 30.0, 301);
        let result = hrf.evaluate(&t).unwrap();
        assert_eq!(result.shape(), &[301, 1]);

        // Should have positive values early and negative undershoot later
        let early_max = result.slice(s![0..100, 0]).fold(f64::NEG_INFINITY, |a, &b| a.max(b));
        let late_min = result.slice(s![100..200, 0]).fold(f64::INFINITY, |a, &b| a.min(b));
        assert!(early_max > 0.0, "Should have positive early response");
        assert!(late_min < 0.0, "Should have negative undershoot");

        // Test with custom parameters
        let hrf2 = lwu_hrf(Some(8.0), Some(3.0), Some(0.5), Some("height")).unwrap();
        let result2 = hrf2.evaluate(&t).unwrap();
        let max_val = result2.fold(f64::NEG_INFINITY, |a, &b| a.max(b.abs()));
        assert_relative_eq!(max_val, 1.0, epsilon = 1e-6);
    }

    #[test]
    fn test_lwu_hrf_validation() {
        // Test invalid sigma
        assert!(lwu_hrf(Some(6.0), Some(0.01), None, None).is_err());

        // Test invalid rho
        assert!(lwu_hrf(Some(6.0), Some(2.5), Some(2.0), None).is_err());
        assert!(lwu_hrf(Some(6.0), Some(2.5), Some(-0.1), None).is_err());

        // Test invalid normalize
        assert!(lwu_hrf(Some(6.0), Some(2.5), Some(0.35), Some("invalid")).is_err());
    }

    #[test]
    fn test_hrf_basis_lwu() {
        let theta0 = [6.0, 2.5, 0.35];
        let hrf = hrf_basis_lwu(&theta0, None).unwrap();

        assert_eq!(hrf.name(), "hrf_basis_lwu");
        assert_eq!(hrf.nbasis(), 4);

        let t = Array1::linspace(0.0, 30.0, 31);
        let result = hrf.evaluate(&t).unwrap();
        assert_eq!(result.shape(), &[31, 4]);

        // First column should be the base LWU HRF
        let base_hrf = lwu_hrf(Some(6.0), Some(2.5), Some(0.35), None).unwrap();
        let base_result = base_hrf.evaluate(&t).unwrap();

        for i in 0..31 {
            assert_relative_eq!(result[[i, 0]], base_result[[i, 0]], epsilon = 1e-6);
        }

        // Other columns should be derivatives (non-zero)
        for col in 1..4 {
            let col_sum: f64 = result.column(col).mapv(|x| x.abs()).sum();
            assert!(col_sum > 0.01, "Derivative column {} should be non-zero", col);
        }
    }

    #[test]
    fn test_hrf_basis_lwu_normalized() {
        let theta0 = [6.0, 2.5, 0.35];
        let hrf = hrf_basis_lwu(&theta0, Some("height")).unwrap();

        let t = Array1::linspace(0.0, 30.0, 301);
        let result = hrf.evaluate(&t).unwrap();

        // First column should be normalized
        let max_val = result.column(0).fold(f64::NEG_INFINITY, |a, &b| a.max(b.abs()));
        assert_relative_eq!(max_val, 1.0, epsilon = 1e-6);
    }

    #[test]
    fn test_hrf_time() {
        let hrf = hrf_time(None);
        assert_eq!(hrf.name(), "hrf_time");
        assert_eq!(hrf.nbasis(), 1);
        assert_eq!(hrf.span(), 22.0);

        let t = Array1::from_vec(vec![0.0, 5.0, 10.0, 15.0, 20.0, 22.0, 25.0]);
        let result = hrf.evaluate(&t).unwrap();

        assert_eq!(result[[0, 0]], 0.0); // t=0 returns 0
        assert_eq!(result[[1, 0]], 5.0); // t=5 returns 5
        assert_eq!(result[[2, 0]], 10.0); // t=10 returns 10
        assert_eq!(result[[3, 0]], 15.0); // t=15 returns 15
        assert_eq!(result[[4, 0]], 20.0); // t=20 returns 20
        assert_eq!(result[[5, 0]], 0.0); // t=22 (maxt) returns 0
        assert_eq!(result[[6, 0]], 0.0); // t=25 (>maxt) returns 0

        // Test with custom maxt
        let hrf2 = hrf_time(Some(30.0));
        assert_eq!(hrf2.span(), 30.0);
        let result2 = hrf2.evaluate(&t).unwrap();
        assert_eq!(result2[[6, 0]], 25.0); // t=25 now returns 25
    }
}

