/// Compute cubic spline coefficients using natural spline boundary conditions.
fn compute_cubic_spline(t: &[f64], y: &[f64]) -> Result<SplineCoefficients> {
    let n = t.len();
    let mut h = vec![0.0; n - 1];
    let mut alpha = vec![0.0; n - 1];

    // Step 1: Calculate h and alpha
    for i in 0..n - 1 {
        h[i] = t[i + 1] - t[i];
        if h[i] <= 0.0 {
            return Err(HrfError::InvalidInput(
                "Time points must be strictly increasing".into(),
            ));
        }
    }

    for i in 1..n - 1 {
        alpha[i] = 3.0 / h[i] * (y[i + 1] - y[i]) - 3.0 / h[i - 1] * (y[i] - y[i - 1]);
    }

    // Step 2: Solve tridiagonal system for c coefficients
    let mut l = vec![1.0; n];
    let mut mu = vec![0.0; n];
    let mut z = vec![0.0; n];

    for i in 1..n - 1 {
        l[i] = 2.0 * (t[i + 1] - t[i - 1]) - h[i - 1] * mu[i - 1];
        mu[i] = h[i] / l[i];
        z[i] = (alpha[i] - h[i - 1] * z[i - 1]) / l[i];
    }

    // Step 3: Back substitution
    let mut c = vec![0.0; n];
    let mut b = vec![0.0; n - 1];
    let mut d = vec![0.0; n - 1];
    let mut a = vec![0.0; n - 1];

    for j in (0..n - 1).rev() {
        c[j] = z[j] - mu[j] * c[j + 1];
        b[j] = (y[j + 1] - y[j]) / h[j] - h[j] * (c[j + 1] + 2.0 * c[j]) / 3.0;
        d[j] = (c[j + 1] - c[j]) / (3.0 * h[j]);
        a[j] = y[j];
    }

    Ok(SplineCoefficients { a, b, c, d })
}

